import React, { useState, useCallback } from 'react';
import { Button, Select, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { DepreciationDto } from '../../../services/tscd/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TEST_ID = 'erp-khau-hao';

const KhauHaoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [data, setData] = useState<DepreciationDto | null>(null);
  const [loading, setLoading] = useState(false);
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);

  const load = useCallback(() => {
    setLoading(true);
    tscdService.getDepreciation(Number(month), Number(year))
      .then(setData)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải khấu hao'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const status = data?.status ?? 'NotRun';
  const canRun = status !== 'Posted';
  const canPost = status === 'Draft';
  const hasLines = (data?.lines.length ?? 0) > 0;

  const handleRun = async () => {
    setRunning(true);
    try {
      await tscdService.runDepreciation(Number(month), Number(year));
      dispatch(addToast({ message: 'Tính khấu hao thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi tính KH'), type: 'error' }));
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    setPosting(true);
    try {
      await tscdService.postDepreciation(Number(month), Number(year));
      dispatch(addToast({ message: 'Ghi sổ khấu hao thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi ghi sổ KH'), type: 'error' }));
    } finally {
      setPosting(false);
    }
  };

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-chart-line" /> Khấu hao TSCĐ</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} data-testid={`${TEST_ID}-month`} />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} data-testid={`${TEST_ID}-year`} />
        <Button variant="primary" onClick={handleRun} loading={running} disabled={!canRun} data-testid={`${TEST_ID}-run`}>Tính KH</Button>
        <Button variant="secondary" onClick={handlePost} loading={posting} disabled={!canPost} data-testid={`${TEST_ID}-post`}>Ghi sổ</Button>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : !data || (status === 'NotRun' && !hasLines) ? (
          <div className={erp.empty}>Chưa tính khấu hao cho kỳ {month}/{year}</div>
        ) : (
          <>
            <div className={erp.summaryBar}>
              <div className={erp.summaryItem}><label className={erp.label}>Trạng thái</label><StatusBadge status={status} /></div>
              <div className={erp.summaryItem}><label className={erp.label}>Tổng KH</label><strong>{formatVnd(data.totalAmount)}</strong></div>
            </div>
            {hasLines ? (
              <div className={erp.tableWrapper}>
                <table className={erp.table}>
                  <thead><tr><th>Mã TS</th><th>Tên</th><th>TK</th><th className={erp.colRight}>Số tiền</th></tr></thead>
                  <tbody>{data.lines.map(l => (
                    <tr key={l.fixedAssetId} data-testid={`${TEST_ID}-row-${l.fixedAssetId}`}>
                      <td><code>{l.assetCode}</code></td>
                      <td>{l.assetName}</td>
                      <td><code>{l.accountCode}</code></td>
                      <td className={erp.colRight}>{formatVnd(l.amount)}</td>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
            ) : (
              <div className={erp.empty}>Không có dòng khấu hao</div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default KhauHaoPage;
